/**
 * Discrete Kraft sum for alphabet size `D` and codeword lengths (toy check, not verified vs Lean).
 * Returns Σᵢ D^(-lᵢ) as a floating-point value.
 */
export function kraftSumFloat(D: number, lengths: readonly number[]): number {
  if (D <= 1 || !Number.isFinite(D)) {
    throw new RangeError('kraftSumFloat: D must be a finite number > 1');
  }
  let s = 0;
  for (const len of lengths) {
    if (len < 1 || !Number.isFinite(len)) {
      throw new RangeError('kraftSumFloat: each length must be a finite number ≥ 1');
    }
    s += D ** -len;
  }
  return s;
}

/**
 * Zeckendorf-style Fibonacci weights for demos: `fibZ(0)…fibZ(count−1)` matching Lean
 * `GnosisMath.fibZ` / `ZeckendorfFST.F` (`1, 1, 2, 3, 5, …`). Not proof-checked in TS.
 *
 * @param count how many weights to return (≥ 0); use `0` for `[]`
 */
export function fibZWeights(count: number): readonly number[] {
  if (!Number.isInteger(count) || count < 0) {
    throw new RangeError('fibZWeights: count must be a non-negative integer');
  }
  if (count === 0) {
    return [];
  }
  if (count === 1) {
    return [1];
  }
  const out: number[] = [1, 1];
  for (let i = 2; i < count; i++) {
    out.push(out[i - 1]! + out[i - 2]!);
  }
  return out;
}
